 1→/**
 2→ * PrismaClient singleton
 3→ *
 4→ * Avoids "too many Prisma Clients" error in development due to hot-reloading.
 5→ * Enables query logging in development for observability.
 6→ */
 7→
 8→import { PrismaClient } from '@prisma/client';
 9→import { PrismaClientOptions } from '@prisma/client/runtime/library';
10→
11→// Global singleton pattern
12→const globalForPrisma = globalThis as unknown as {
13→  prisma: PrismaClient | undefined;
14→};
15→
16→/**
17→ * Prisma client configuration with development logging
18→ */
19→const prismaOptions: PrismaClientOptions = {
20→  log: process.env.NODE_ENV === 'development'
21→    ? ['query', 'error', 'warn'] as const
22→    : ['error'] as const,
23→};
24→
25→/**
26→ * Singleton PrismaClient instance
27→ * Reuses existing instance in hot-reload scenarios
28→ */
29→export const prisma =
30→  globalForPrisma.prisma ??
31→  new PrismaClient(prismaOptions);
32→
33→if (process.env.NODE_ENV !== 'production') {
34→  globalForPrisma.prisma = prisma;
35→}
36→
37→/**
38→ * Graceful shutdown hook
39→ * Call this before process exit to close database connections
40→ */
41→export async function disconnectPrisma(): Promise<void> {
42→  await prisma.$disconnect();
43→}
44→
45→export default prisma;
